import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Save, 
  Loader2, Crown, Users, Key, ChevronDown, 
  Settings, Zap, CheckCircle2, Lock
} from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [novoNome, setNovoNome] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => { carregarDados(); }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return setErroLocal("Sessão expirada.");

      const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle();

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista } = await supabase.from('profiles').select('*').order('nome', { ascending: true });
          if (lista) setUsuarios(lista);
        }
      }
    } catch (err) { setErroLocal("Erro ao carregar dados."); } 
    finally { setLoading(false); }
  };

  const atualizarNome = async () => {
    const { error } = await supabase.from('profiles').update({ nome: novoNome }).eq('id', perfil.id);
    if (!error) { setPerfil({ ...perfil, nome: novoNome }); alert("✨ Nome atualizado com sucesso!"); }
  };

  const alterarSenha = async () => {
    if (novaSenha.length < 6) return alert("A senha deve ter pelo menos 6 caracteres.");
    const { error } = await supabase.auth.updateUser({ password: novaSenha });
    if (!error) { alert("🔒 Segurança reforçada! Senha alterada."); setNovaSenha(''); }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    const { error } = await supabase.from('profiles').update({ tipo_usuario: novoCargo }).eq('id', usuarioId);
    if (!error) setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
  };

  const excluirUsuario = async (id, nome) => {
    if (id === perfil.id) return;
    if (window.confirm(`Remover permanentemente ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) setUsuarios(usuarios.filter(u => u.id !== id));
    }
  };

  if (loading) return (
    <div style={containerCenter}>
      <Loader2 className="animate-spin" size={48} color="#6366f1" />
      <span style={{marginTop: '15px', fontWeight: 600, color: '#6366f1'}}>Preparando sua experiência...</span>
    </div>
  );

  return (
    <div style={pageWrapper}>
      <div style={contentContainer}>
        
        {/* HEADER PREMIUM */}
        <header style={headerStyle}>
          <div style={iconBadge}><Settings size={28} color="#fff" /></div>
          <div>
            <h1 style={mainTitle}>Centro de Comando</h1>
            <p style={subTitle}>Gerencie sua identidade e acessos ao sistema</p>
          </div>
        </header>

        <div style={gridContainer}>
          
          {/* CARD DE INFORMAÇÕES PESSOAIS */}
          <div style={glassCard}>
            <div style={cardHeader}>
              <Zap size={20} color="#6366f1" />
              <h3 style={cardTitle}>Dados Pessoais</h3>
            </div>
            
            <div style={inputGroup}>
              <label style={premiumLabel}>Nome de Exibição</label>
              <div style={inputWrapper}>
                <User size={18} style={inputIcon} />
                <input value={novoNome} onChange={(e) => setNovoNome(e.target.value)} style={premiumInput} />
                <button onClick={atualizarNome} style={saveActionBtn}><CheckCircle2 size={20} /></button>
              </div>
            </div>

            <div style={staticInfoGroup}>
              <div style={infoBox}>
                <label style={premiumLabel}>E-mail</label>
                <div style={infoText}><Mail size={14} /> {perfil?.email}</div>
              </div>
              <div style={infoBox}>
                <label style={premiumLabel}>Nível de Acesso</label>
                <div style={badgeStyle(perfil?.tipo_usuario)}>{perfil?.tipo_usuario}</div>
              </div>
            </div>
          </div>

          {/* CARD DE SEGURANÇA */}
          <div style={glassCard}>
            <div style={cardHeader}>
              <Lock size={20} color="#f43f5e" />
              <h3 style={cardTitle}>Segurança</h3>
            </div>
            <div style={inputGroup}>
              <label style={premiumLabel}>Nova Senha</label>
              <div style={inputWrapper}>
                <Key size={18} style={inputIcon} />
                <input type="password" placeholder="••••••••" value={novaSenha} onChange={(e) => setNovaSenha(e.target.value)} style={premiumInput} />
              </div>
            </div>
            <button onClick={alterarSenha} style={gradientBtn}>Atualizar Credenciais</button>
          </div>

        </div>

        {/* ÁREA DE GESTÃO (SÓ PROPRIETÁRIO) */}
        {perfil?.tipo_usuario === 'proprietario' && (
          <section style={{ marginTop: '60px' }}>
            <div style={adminHeader}>
              <Users size={24} color="#0f172a" />
              <h2 style={adminTitle}>Gestão de Membros</h2>
              <span style={userCountBadge}>{usuarios.length} usuários</span>
            </div>

            <div style={userTableWrapper}>
              {usuarios.map(u => (
                <div key={u.id} style={userRow}>
                  <div style={userAvatarContainer}>
                    {u.tipo_usuario === 'proprietario' ? <Crown size={16} color="#eab308" /> : u.nome.charAt(0)}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={userName}>{u.nome} {u.id === perfil.id && "(Você)"}</div>
                    <div style={userEmail}>{u.email}</div>
                  </div>
                  
                  <div style={actionsContainer}>
                    {u.id !== perfil.id && (
                      <>
                        <div style={selectContainer}>
                          <select 
                            value={u.tipo_usuario} 
                            onChange={(e) => mudarCargo(u.id, e.target.value)}
                            style={premiumSelect}
                          >
                            <option value="comum">Comum</option>
                            <option value="proprietario">Proprietário</option>
                          </select>
                          <ChevronDown size={14} style={selectChevron} />
                        </div>
                        <button onClick={() => excluirUsuario(u.id, u.nome)} style={deleteIconBtn}><Trash2 size={18} /></button>
                      </>
                    )}
                    {u.id === perfil.id && <div style={badgeStyle(u.tipo_usuario)}>Ativo</div>}
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}
      </div>
    </div>
  );
};

// --- DESIGN SYSTEM PREMIUM (STYLES) ---
const pageWrapper = { minHeight: '100vh', background: '#f8fafc', fontFamily: '"Inter", sans-serif' };
const contentContainer = { maxWidth: '1100px', margin: '0 auto', padding: '60px 20px' };
const containerCenter = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '80vh' };

const headerStyle = { display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '50px' };
const iconBadge = { padding: '12px', background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', borderRadius: '16px', boxShadow: '0 10px 15px -3px rgba(79, 70, 229, 0.4)' };
const mainTitle = { fontSize: '2.5rem', fontWeight: 900, color: '#0f172a', margin: 0, letterSpacing: '-1px' };
const subTitle = { color: '#64748b', fontSize: '1.1rem', margin: '5px 0 0' };

const gridContainer = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '30px' };
const glassCard = { background: '#ffffff', padding: '32px', borderRadius: '24px', border: '1px solid #f1f5f9', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 10px 15px -3px rgba(0, 0, 0, 0.03)' };

const cardHeader = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '25px' };
const cardTitle = { fontSize: '1.25rem', fontWeight: 700, color: '#1e293b', margin: 0 };

const inputGroup = { marginBottom: '25px' };
const premiumLabel = { display: 'block', fontSize: '0.75rem', fontWeight: 800, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '8px' };
const inputWrapper = { position: 'relative', display: 'flex', alignItems: 'center' };
const inputIcon = { position: 'absolute', left: '16px', color: '#cbd5e1' };
const premiumInput = { width: '100%', padding: '14px 16px 14px 45px', borderRadius: '14px', border: '2px solid #f1f5f9', fontSize: '1rem', fontWeight: 500, outline: 'none', transition: 'all 0.3s focus', backgroundColor: '#fdfdfd' };
const saveActionBtn = { position: 'absolute', right: '10px', background: '#6366f1', color: '#fff', border: 'none', borderRadius: '10px', width: '36px', height: '36px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };

const staticInfoGroup = { display: 'flex', gap: '15px' };
const infoBox = { flex: 1, padding: '15px', background: '#f8fafc', borderRadius: '16px' };
const infoText = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.9rem', fontWeight: 600, color: '#475569' };

const gradientBtn = { width: '100%', padding: '16px', background: 'linear-gradient(135deg, #0f172a 0%, #334155 100%)', color: '#fff', border: 'none', borderRadius: '16px', fontWeight: 700, cursor: 'pointer', boxShadow: '0 10px 15px -3px rgba(15, 23, 42, 0.3)', transition: 'transform 0.2s' };

const adminHeader = { display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '30px' };
const adminTitle = { fontSize: '1.5rem', fontWeight: 800, color: '#0f172a', margin: 0 };
const userCountBadge = { background: '#e2e8f0', padding: '4px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 700, color: '#475569' };

const userTableWrapper = { display: 'grid', gap: '12px' };
const userRow = { display: 'flex', alignItems: 'center', padding: '16px 24px', background: '#fff', borderRadius: '20px', border: '1px solid #f1f5f9', transition: 'transform 0.2s hover' };
const userAvatarContainer = { width: '45px', height: '45px', borderRadius: '14px', background: '#f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800, color: '#6366f1', marginRight: '15px' };
const userName = { fontWeight: 700, color: '#1e293b', fontSize: '1rem' };
const userEmail = { fontSize: '0.85rem', color: '#94a3b8' };

const actionsContainer = { display: 'flex', alignItems: 'center', gap: '15px' };
const selectContainer = { position: 'relative' };
const premiumSelect = { appearance: 'none', padding: '8px 35px 8px 15px', borderRadius: '10px', border: '1px solid #e2e8f0', fontSize: '0.85rem', fontWeight: 600, background: '#fff', cursor: 'pointer' };
const selectChevron = { position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: '#94a3b8' };
const deleteIconBtn = { padding: '10px', background: '#fff1f2', color: '#f43f5e', border: 'none', borderRadius: '10px', cursor: 'pointer' };

const badgeStyle = (tipo) => ({
  display: 'inline-flex', padding: '6px 14px', borderRadius: '10px', fontSize: '0.75rem', fontWeight: 800, textTransform: 'uppercase',
  backgroundColor: tipo === 'proprietario' ? '#6366f115' : '#f59e0b15',
  color: tipo === 'proprietario' ? '#6366f1' : '#d97706'
});

export default Perfil;
